CREATE DATABASE Insurance_Management_System;
USE Insurance_Management_System;
CREATE TABLE Branch (
    Branch_ID INT PRIMARY KEY AUTO_INCREMENT,
    Branch_Name VARCHAR(100),
    Branch_Address VARCHAR(200),
    City VARCHAR(50),
    State VARCHAR(50),
    Phone VARCHAR(15)
);
DELETE FROM Branch;
CREATE TABLE Employee (
    Employee_ID INT PRIMARY KEY AUTO_INCREMENT,
    Branch_ID INT,
    First_Name VARCHAR(50),
    Last_Name VARCHAR(50),
    Gender VARCHAR(10),
    DOB DATE,
    Phone VARCHAR(15),
    Email VARCHAR(100),
    Designation VARCHAR(50),
    Salary DECIMAL(10,2),
    Hire_Date DATE,
    FOREIGN KEY (Branch_ID) REFERENCES Branch(Branch_ID)
);
CREATE TABLE Agent (
    Agent_ID INT PRIMARY KEY AUTO_INCREMENT,
    Branch_ID INT,
    First_Name VARCHAR(50),
    Last_Name VARCHAR(50),
    Phone VARCHAR(15),
    Email VARCHAR(100),
    Commission_Rate DECIMAL(5,2),
    FOREIGN KEY (Branch_ID) REFERENCES Branch(Branch_ID)
);
CREATE TABLE Customer (
    Customer_ID INT PRIMARY KEY AUTO_INCREMENT,
    First_Name VARCHAR(50),
    Last_Name VARCHAR(50),
    Gender VARCHAR(10),
    DOB DATE,
    Phone VARCHAR(15),
    Email VARCHAR(100) UNIQUE,
    Address VARCHAR(200),
    City VARCHAR(50),
    State VARCHAR(50),
    Pincode VARCHAR(10)
);
CREATE TABLE Policy_Type (
    PolicyType_ID INT PRIMARY KEY AUTO_INCREMENT,
    Policy_Name VARCHAR(100),
    Coverage_Amount DECIMAL(12,2),
    Premium DECIMAL(10,2),
    Duration_Years INT
);
CREATE TABLE Policy (
    Policy_ID INT PRIMARY KEY AUTO_INCREMENT,
    Customer_ID INT,
    Agent_ID INT,
    PolicyType_ID INT,
    Start_Date DATE,
    End_Date DATE,
    Status VARCHAR(20),
    FOREIGN KEY (Customer_ID) REFERENCES Customer(Customer_ID),
    FOREIGN KEY (Agent_ID) REFERENCES Agent(Agent_ID),
    FOREIGN KEY (PolicyType_ID) REFERENCES Policy_Type(PolicyType_ID)
);
CREATE TABLE Nominee (
    Nominee_ID INT PRIMARY KEY AUTO_INCREMENT,
    Customer_ID INT,
    Nominee_Name VARCHAR(100),
    Relationship VARCHAR(50),
    Phone VARCHAR(15),
    FOREIGN KEY (Customer_ID) REFERENCES Customer(Customer_ID)
CREATE TABLE Premium_Payment (
    Payment_ID INT PRIMARY KEY AUTO_INCREMENT,
    Policy_ID INT,
    Payment_Date DATE,
    Amount DECIMAL(10,2),
    Payment_Method VARCHAR(30),
    Payment_Status VARCHAR(20),
    FOREIGN KEY (Policy_ID) REFERENCES Policy(Policy_ID)
);
CREATE TABLE Claim (
    Claim_ID INT PRIMARY KEY AUTO_INCREMENT,
    Policy_ID INT,
    Claim_Date DATE,
    Claim_Amount DECIMAL(12,2),
    Claim_Status VARCHAR(20),
    Reason VARCHAR(200),
    FOREIGN KEY (Policy_ID) REFERENCES Policy(Policy_ID)
);
CREATE TABLE Claim_Document (
    Document_ID INT PRIMARY KEY AUTO_INCREMENT,
    Claim_ID INT,
    Document_Name VARCHAR(100),
    Upload_Date DATE,
    Verification_Status VARCHAR(20),
    FOREIGN KEY (Claim_ID) REFERENCES Claim(Claim_ID)
);
CREATE TABLE Vehicle (
    Vehicle_ID INT PRIMARY KEY AUTO_INCREMENT,
    Customer_ID INT,
    Vehicle_Number VARCHAR(20),
    Vehicle_Type VARCHAR(50),
    Brand VARCHAR(50),
    Model VARCHAR(50),
    Manufacturing_Year INT,
    FOREIGN KEY (Customer_ID) REFERENCES Customer(Customer_ID)
);
CREATE TABLE Policy_Renewal (
    Renewal_ID INT PRIMARY KEY AUTO_INCREMENT,
    Policy_ID INT,
    Renewal_Date DATE,
    Next_Due_Date DATE,
    Renewal_Status VARCHAR(20),
    FOREIGN KEY (Policy_ID) REFERENCES Policy(Policy_ID)
);
CREATE TABLE Payment (
    Payment_Record_ID INT PRIMARY KEY AUTO_INCREMENT,
    Policy_ID INT,
    Amount DECIMAL(10,2),
    Payment_Date DATE,
    Payment_Mode VARCHAR(20),
    Transaction_ID VARCHAR(100),
    FOREIGN KEY (Policy_ID) REFERENCES Policy(Policy_ID)
);
CREATE TABLE Invoice (
    Invoice_ID INT PRIMARY KEY AUTO_INCREMENT,
    Policy_ID INT,
    Invoice_Date DATE,
    Amount DECIMAL(10,2),
    Tax DECIMAL(10,2),
    Total DECIMAL(10,2),
    FOREIGN KEY (Policy_ID) REFERENCES Policy(Policy_ID)
);
CREATE TABLE Feedback (
    Feedback_ID INT PRIMARY KEY AUTO_INCREMENT,
    Customer_ID INT,
    Rating INT,
    Comments VARCHAR(300),
    Feedback_Date DATE,
    FOREIGN KEY (Customer_ID) REFERENCES Customer(Customer_ID)
);
